export function yield_(child?: (T.Expression | T.Expressions)) {
  const children = child != null ? [child] : [];
  return withMethods({
    $type: TSKindId.Yield as number,
    $source: 2 as const,
    $named: true as const,
    $children: children,
    children() { return children; },
    $with: { $child: (v: (T.Expression | T.Expressions)) => yield_(v) },
  });
}

